import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import prescriptionService from '../../services/prescriptionService';

function PrescriptionDetailPage() {
  const { id }    = useParams();
  const navigate  = useNavigate();
  const [rx, setRx]           = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    prescriptionService.getPrescription(id)
      .then(data => setRx(data.data))
      .catch(() => { toast.error('Prescription not found.'); navigate('/prescriptions'); })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return (
    <div className="flex justify-center py-24">
      <svg className="animate-spin w-8 h-8 text-teal-500" fill="none" viewBox="0 0 24 24">
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
      </svg>
    </div>
  );

  if (!rx) return null;

  return (
    <div className="max-w-xl mx-auto space-y-4">
      <button onClick={() => navigate('/prescriptions')}
        className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-teal-600">
        ← Back to Prescriptions
      </button>

      {/* Prescription Header */}
      <div className="bg-gradient-to-r from-teal-700 to-teal-900 rounded-xl p-5 text-white">
        <div className="flex items-center gap-2 mb-1">
          <span className="text-2xl">💊</span>
          <h1 className="font-bold text-base">Prescription</h1>
        </div>
        <p className="text-teal-200 text-xs">
          {new Date(rx.created_at).toLocaleDateString('en-IN', {
            weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
          })}
        </p>
      </div>

      {/* Doctor + Patient Info */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
          <p className="text-xs text-gray-400 mb-1 uppercase tracking-wide">Doctor</p>
          <p className="text-sm font-semibold text-gray-900">{rx.doctor_name}</p>
          <p className="text-xs text-gray-500 mt-0.5">{rx.doctor_specialization}</p>
          <p className="text-xs text-gray-400 mt-0.5">🏥 {rx.hospital_name}</p>
        </div>
        <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
          <p className="text-xs text-gray-400 mb-1 uppercase tracking-wide">Patient</p>
          <p className="text-sm font-semibold text-gray-900">{rx.patient_name}</p>
          <p className="text-xs text-gray-500 mt-0.5">{rx.patient_phone}</p>
          <p className="text-xs text-gray-400 mt-0.5">{rx.patient_email}</p>
        </div>
      </div>

      {/* Diagnosis */}
      <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 className="text-xs font-semibold text-gray-700 uppercase tracking-wide mb-2">
          Diagnosis
        </h3>
        <p className="text-sm text-gray-800">{rx.diagnosis}</p>
      </div>

      {/* Medicines */}
      <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 className="text-xs font-semibold text-gray-700 uppercase tracking-wide mb-3">
          Medicines ({rx.medicines?.length || 0})
        </h3>
        <div className="space-y-3">
          {rx.medicines?.map((med, i) => (
            <div key={i}
              className="flex items-start gap-3 p-3 bg-teal-50
                         border border-teal-100 rounded-lg">
              <div className="w-6 h-6 bg-teal-600 rounded-full flex items-center
                              justify-center text-white text-xs font-bold flex-shrink-0">
                {i + 1}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-gray-900">{med.name}</p>
                <div className="flex flex-wrap gap-3 mt-1 text-xs text-gray-600">
                  <span>💊 {med.dosage}</span>
                  <span>⏱ {med.duration}</span>
                </div>
                {med.instructions && (
                  <p className="text-xs text-gray-500 mt-1">
                    📝 {med.instructions}
                  </p>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Instructions */}
      {rx.instructions && (
        <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
          <h3 className="text-xs font-semibold text-gray-700 uppercase tracking-wide mb-2">
            General Instructions
          </h3>
          <p className="text-sm text-gray-700">{rx.instructions}</p>
        </div>
      )}

      {/* Follow up */}
      {rx.follow_up_date && (
        <div className="bg-orange-50 border border-orange-200 rounded-xl p-4
                        flex items-center gap-3">
          <span className="text-xl">🔄</span>
          <div>
            <p className="text-xs font-semibold text-orange-800">Follow-up Date</p>
            <p className="text-sm text-orange-700 font-medium">
              {new Date(rx.follow_up_date).toLocaleDateString('en-IN', {
                weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
              })}
            </p>
          </div>
        </div>
      )}

      {/* Download */}
      {rx.prescription_file_url && (
        <a href={rx.prescription_file_url} target="_blank" rel="noreferrer"
          className="flex items-center justify-center gap-2 w-full py-3
                     text-sm font-medium text-white bg-teal-600 rounded-xl
                     hover:bg-teal-700 transition-colors">
          ⬇️ Download Prescription PDF
        </a>
      )}
    </div>
  );
}

export default PrescriptionDetailPage;
